/* ==========================================================================
   SKIN: Neumorphic / Soft-UI   ·   [data-skin="neumorphic"]
   One monochrome surface; depth comes purely from paired light/dark soft
   shadows. Controls look extruded from (raised) or pressed into (inset) the
   page. Borderless. Pure CSS over stock shadcn.

   CONFIGURABILITY: every depth value is composed from a handful of shape
   knobs (--neu-distance, --neu-blur, --neu-tint, --neu-elevate, --neu-glow) via calc()
   and color-mix(). Brand colour, surfaces, borders and radii are routed
   through the standard tokens (--primary, --card, --border, --radius …) so
   the editor genuinely retunes the whole skin from one place.
   ========================================================================== */

:root[data-skin="neumorphic"] {
  --app-font-sans: "Poppins", "Segoe UI", system-ui, -apple-system, sans-serif;
  --app-font-heading: var(--app-font-sans);
  --app-font-mono: ui-monospace, "SF Mono", monospace;
  --app-font-size: 14px;

  --radius: 14px;

  /* One monochrome clay surface. Everything derives from these. */
  --background: #e0e5ec;
  --foreground: #3a424e;          /* darkened for WCAG body text */
  --card: #e0e5ec;
  --card-foreground: #3a424e;
  --popover: #e0e5ec;
  --popover-foreground: #3a424e;
  --primary: #6d5dfc;
  --primary-foreground: #ffffff;
  --secondary: #e0e5ec;
  --secondary-foreground: #3a424e;
  --muted: #e0e5ec;
  --muted-foreground: #566375;    /* darkened to clear WCAG AA 4.5:1 on #e0e5ec */
  --accent: #6d5dfc;
  --accent-foreground: #ffffff;
  --destructive: #d23a55;
  --destructive-foreground: #ffffff;
  --border: #d1d9e6;
  --input: #d1d9e6;
  --ring: #6d5dfc;
  --chart-1: #6d5dfc;
  --chart-2: #8b7dff;
  --chart-3: #a99bff;
  --chart-4: #5a4bd8;
  --chart-5: #c0b8ff;
  --sidebar: #e0e5ec;
  --sidebar-foreground: #3a424e;
  --sidebar-accent: #6d5dfc;
  --sidebar-accent-foreground: #ffffff;
  --sidebar-border: #d1d9e6;

  /* Ink-grade primary for TEXT on the clay surface — #6d5dfc on #e0e5ec is
     only 3.59:1, so text usages darken toward ink to clear WCAG AA (4.5:1).
     Fills keep var(--primary), where white-on-primary passes at 4.54:1. */
  --neu-primary-ink: color-mix(in srgb, var(--primary) 75%, #1f2430);

  /* ---- Tunable shape knobs (editor sliders) ---------------------------- */
  /* How far controls extrude from the surface. */
  --neu-distance: 6px;
  /* Softness of the paired shadows. */
  --neu-blur: 12px;
  /* Light/shadow contrast of the clay (0 = flat, 1 = crisp). Drives the
     two highlight/shade tones via color-mix so one knob sets the whole
     skin's tactility. */
  --neu-tint: 0.5;
  /* Extra elevation multiplier for top-level containers vs inline controls. */
  --neu-elevate: 2;
  /* Glow of the focus ring + colour bleed of raised coloured fills. */
  --neu-glow: 4px;

  /* Derived light/shade tones — color-mix lets --neu-tint scale contrast. */
  --neu-light: color-mix(in srgb, #ffffff calc(var(--neu-tint) * 70% + 30%), var(--background));
  --neu-dark:  color-mix(in srgb, color-mix(in srgb, var(--border) 62%, var(--muted-foreground)) calc(var(--neu-tint) * 80% + 20%), var(--background));

  /* Secondary distance/blur for small inline controls. */
  --neu-d2: calc(var(--neu-distance) * 0.66);
  --neu-b2: calc(var(--neu-blur) * 0.66);

  /* Raised: extruded out of the surface. */
  --neu-raised-sm:
    var(--neu-d2) var(--neu-d2) var(--neu-b2) var(--neu-dark),
    calc(var(--neu-d2) * -1) calc(var(--neu-d2) * -1) var(--neu-b2) var(--neu-light);
  --neu-raised:
    var(--neu-distance) var(--neu-distance) var(--neu-blur) var(--neu-dark),
    calc(var(--neu-distance) * -1) calc(var(--neu-distance) * -1) var(--neu-blur) var(--neu-light);
  /* Large elevation for top-level containers (cards, dialogs, app bar). */
  --neu-raised-lg:
    calc(var(--neu-distance) * var(--neu-elevate)) calc(var(--neu-distance) * var(--neu-elevate)) calc(var(--neu-blur) * var(--neu-elevate)) var(--neu-dark),
    calc(var(--neu-distance) * var(--neu-elevate) * -1) calc(var(--neu-distance) * var(--neu-elevate) * -1) calc(var(--neu-blur) * var(--neu-elevate)) var(--neu-light);

  /* Inset: pressed into the surface. */
  --neu-inset:
    inset var(--neu-d2) var(--neu-d2) var(--neu-b2) var(--neu-dark),
    inset calc(var(--neu-d2) * -1) calc(var(--neu-d2) * -1) var(--neu-b2) var(--neu-light);
  --neu-inset-sm:
    inset calc(var(--neu-distance) * 0.33) calc(var(--neu-distance) * 0.33) calc(var(--neu-blur) * 0.42) var(--neu-dark),
    inset calc(var(--neu-distance) * -0.33) calc(var(--neu-distance) * -0.33) calc(var(--neu-blur) * 0.42) var(--neu-light);

  /* Drop shadow tuned for COLOURED fills — neutral light/dark clay shadows
     look wrong on purple, so coloured extrusions get a tinted drop + an
     inner top highlight that reads against the fill itself. NOTE: custom
     properties declared at this level inherit with var() ALREADY substituted,
     so overriding --neu-fill-color alone in a descendant retargets nothing —
     variants (destructive, etc.) must re-declare the full gradient/shadow
     recipe locally. */
  --neu-fill-color: var(--primary);
  /* Coloured-fill gradient written against --neu-fill-color; like
     --neu-raised-fill, variants must re-declare it locally because the
     :root-level value inherits with var(--neu-fill-color) baked in. */
  --neu-fill-gradient: linear-gradient(145deg, var(--neu-fill-color), color-mix(in srgb, var(--neu-fill-color) 90%, #000000));
  --neu-raised-fill:
    inset 0 1px 1px color-mix(in srgb, #ffffff 55%, transparent),
    inset 0 -2px 4px color-mix(in srgb, #000000 18%, transparent),
    var(--neu-d2) var(--neu-d2) calc(var(--neu-blur) * 0.9) color-mix(in srgb, var(--neu-fill-color) 35%, transparent);

  /* Focus halo that survives the soft shadows (used on every control). */
  --neu-focus-ring: 0 0 0 calc(var(--neu-glow) * 0.5) color-mix(in srgb, var(--ring) 90%, transparent);
}

[data-skin="neumorphic"] body { background: var(--background); color: var(--foreground); }
[data-skin="neumorphic"] ::selection {
  background: color-mix(in srgb, var(--primary) 22%, var(--background));
  color: var(--foreground);
}

/* ---- Shell -------------------------------------------------------------- */
[data-skin="neumorphic"] .app-bar {
  background: var(--background);
  border: 0;
  border-radius: calc(var(--radius) + 4px);
  box-shadow: var(--neu-raised-lg);
  backdrop-filter: none;
}
[data-skin="neumorphic"] .app-brand { font-weight: 700; color: var(--foreground); }

[data-skin="neumorphic"] .app-nav-inner {
  border: 0;
  border-radius: calc(var(--radius) + 4px);
  background: var(--background);
  box-shadow: var(--neu-raised-lg);
  padding: 12px;
}
[data-skin="neumorphic"] .app-nav a {
  border-radius: calc(var(--radius) - 4px);
  color: var(--foreground);
  transition: box-shadow 140ms ease, color 140ms ease;
}
[data-skin="neumorphic"] .app-nav a:hover {
  background: var(--background);
  color: var(--neu-primary-ink);
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] .app-nav a[aria-current="page"],
[data-skin="neumorphic"] .app-nav a[data-active="true"] {
  color: var(--neu-primary-ink);
  box-shadow: var(--neu-inset-sm);
}

[data-skin="neumorphic"] .hero {
  border: 0;
  border-radius: calc(var(--radius) + 8px);
  background: var(--background);
  box-shadow: var(--neu-raised-lg);
}
[data-skin="neumorphic"] .hero-title { color: var(--foreground); }
[data-skin="neumorphic"] .hero-sub { color: var(--muted-foreground); }

[data-skin="neumorphic"] .specimen {
  border: 0;
  border-radius: calc(var(--radius) + 8px);
  background: var(--background);
  box-shadow: var(--neu-raised-lg);
  overflow: visible;
}
[data-skin="neumorphic"] .specimen-head { border-bottom: 0; }
[data-skin="neumorphic"] .specimen-title { color: var(--foreground); font-weight: 700; }
[data-skin="neumorphic"] .specimen-tag {
  color: var(--muted-foreground);
  font-family: var(--app-font-mono);
  letter-spacing: 0.04em;
}

[data-skin="neumorphic"] .app-status {
  border: 0;
  border-radius: calc(var(--radius) + 2px);
  background: var(--background);
  box-shadow: var(--neu-raised-sm);
  color: var(--muted-foreground);
}

/* ---- Controls ----------------------------------------------------------- */
/* Base = raised soft pill. Variants below break the tie so default / secondary
   / outline / ghost / destructive each read distinctly. */
[data-skin="neumorphic"] .group\/button {
  border: 0;
  border-radius: calc(var(--radius) - 2px);
  background: var(--background);
  color: var(--foreground);
  font-weight: 600;
  box-shadow: var(--neu-raised-sm);
  transition: box-shadow 140ms ease, color 140ms ease, transform 100ms ease;
}
[data-skin="neumorphic"] .group\/button:hover { color: var(--neu-primary-ink); }
[data-skin="neumorphic"] .group\/button:active:not(:disabled),
[data-skin="neumorphic"] .group\/button[data-state="open"],
[data-skin="neumorphic"] .group\/button[aria-expanded="true"] {
  box-shadow: var(--neu-inset-sm);
  color: var(--neu-primary-ink);
}
/* Perceivable focus halo on top of whatever shadow state is active. */
[data-skin="neumorphic"] .group\/button:focus-visible {
  outline: 0;
  box-shadow: var(--neu-raised-sm), var(--neu-focus-ring);
}

/* DEFAULT — the one true raised brand control: coloured fill, tinted drop. */
[data-skin="neumorphic"] .group\/button[data-variant="default"] {
  background: var(--neu-fill-gradient);
  color: var(--primary-foreground);
  font-weight: 700;
  box-shadow: var(--neu-raised-fill);
}
[data-skin="neumorphic"] .group\/button[data-variant="default"]:hover { color: var(--primary-foreground); filter: brightness(1.04); }
[data-skin="neumorphic"] .group\/button[data-variant="default"]:active:not(:disabled),
[data-skin="neumorphic"] .group\/button[data-variant="default"][data-state="open"],
[data-skin="neumorphic"] .group\/button[data-variant="default"][aria-expanded="true"] {
  box-shadow:
    inset 0 2px 5px color-mix(in srgb, #000000 28%, transparent),
    inset 0 1px 1px color-mix(in srgb, #ffffff 30%, transparent);
  color: var(--primary-foreground);
  filter: none;
}
[data-skin="neumorphic"] .group\/button[data-variant="default"]:focus-visible {
  box-shadow: var(--neu-raised-fill), var(--neu-focus-ring);
}

/* SECONDARY — raised neutral clay, muted ink. */
[data-skin="neumorphic"] .group\/button[data-variant="secondary"] {
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-raised-sm);
}

/* OUTLINE — resting "pressed in" carved state to distinguish from raised. */
[data-skin="neumorphic"] .group\/button[data-variant="outline"] {
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] .group\/button[data-variant="outline"]:hover { color: var(--neu-primary-ink); }

/* GHOST — perfectly flat until hover, then lifts. */
[data-skin="neumorphic"] .group\/button[data-variant="ghost"] {
  background: transparent;
  box-shadow: none;
  color: var(--foreground);
}
[data-skin="neumorphic"] .group\/button[data-variant="ghost"]:hover {
  color: var(--neu-primary-ink);
  box-shadow: var(--neu-raised-sm);
}

/* DESTRUCTIVE — coloured fill like default but red, white text (AA).
   Same --neu-raised-fill recipe, retargeted via --neu-fill-color. */
[data-skin="neumorphic"] .group\/button[data-variant="destructive"] {
  --neu-fill-color: var(--destructive);
  --neu-fill-gradient: linear-gradient(145deg, var(--neu-fill-color), color-mix(in srgb, var(--neu-fill-color) 90%, #000000));
  --neu-raised-fill:
    inset 0 1px 1px color-mix(in srgb, #ffffff 55%, transparent),
    inset 0 -2px 4px color-mix(in srgb, #000000 18%, transparent),
    var(--neu-d2) var(--neu-d2) calc(var(--neu-blur) * 0.9) color-mix(in srgb, var(--neu-fill-color) 35%, transparent);
  background: var(--neu-fill-gradient);
  color: var(--destructive-foreground);
  font-weight: 700;
  box-shadow: var(--neu-raised-fill);
}
[data-skin="neumorphic"] .group\/button[data-variant="destructive"]:hover { color: var(--destructive-foreground); filter: brightness(1.04); }
/* Pressed / held-open destructive keeps white text + pressed-fill insets
   instead of the generic grey clay inset + ink-on-fill combination. */
[data-skin="neumorphic"] .group\/button[data-variant="destructive"]:active:not(:disabled),
[data-skin="neumorphic"] .group\/button[data-variant="destructive"][data-state="open"],
[data-skin="neumorphic"] .group\/button[data-variant="destructive"][aria-expanded="true"] {
  color: var(--destructive-foreground);
  box-shadow:
    inset 0 2px 5px color-mix(in srgb, #000000 28%, transparent),
    inset 0 1px 1px color-mix(in srgb, #ffffff 30%, transparent);
  filter: none;
}

/* LINK — flat underlined brand text. */
[data-skin="neumorphic"] .group\/button[data-variant="link"] {
  box-shadow: none;
  background: transparent;
  color: var(--neu-primary-ink);
  text-decoration: underline;
  text-underline-offset: 3px;
}

/* Variant-aware focus: append the halo to each variant's RESTING shadow so
   focusing an inset (outline) or flat (ghost/link) button never pops it to
   raised. Placed after the variant rules so they win the cascade. */
[data-skin="neumorphic"] .group\/button[data-variant="secondary"]:focus-visible {
  box-shadow: var(--neu-raised-sm), var(--neu-focus-ring);
}
[data-skin="neumorphic"] .group\/button[data-variant="outline"]:focus-visible {
  box-shadow: var(--neu-inset-sm), var(--neu-focus-ring);
}
[data-skin="neumorphic"] .group\/button[data-variant="ghost"]:focus-visible,
[data-skin="neumorphic"] .group\/button[data-variant="link"]:focus-visible {
  box-shadow: var(--neu-focus-ring);
}
[data-skin="neumorphic"] .group\/button[data-variant="destructive"]:focus-visible {
  box-shadow: var(--neu-raised-fill), var(--neu-focus-ring);
}

/* DISABLED — flat, muted, visibly non-interactive across every variant:
   no bevel, no glow, no coloured fill. */
[data-skin="neumorphic"] .group\/button:disabled,
[data-skin="neumorphic"] .group\/button[data-variant]:disabled {
  background: var(--background);
  box-shadow: none;
  color: var(--muted-foreground);
  filter: none;
  transform: none;
}

[data-skin="neumorphic"] [data-slot="input"],
[data-skin="neumorphic"] [data-slot="textarea"],
[data-skin="neumorphic"] [data-slot="select-trigger"],
[data-skin="neumorphic"] .skin-select {
  border: 0;
  border-radius: calc(var(--radius) - 2px);
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-inset);
}
[data-skin="neumorphic"] [data-slot="input"]::placeholder,
[data-skin="neumorphic"] [data-slot="textarea"]::placeholder { color: var(--muted-foreground); }
[data-skin="neumorphic"] [data-slot="input"]:focus-visible,
[data-skin="neumorphic"] [data-slot="textarea"]:focus-visible,
[data-skin="neumorphic"] [data-slot="select-trigger"]:focus-visible {
  outline: 0;
  box-shadow: var(--neu-inset), var(--neu-focus-ring);
}
/* Disabled fields go shallow + muted so they stop reading as editable wells. */
[data-skin="neumorphic"] [data-slot="input"]:disabled,
[data-skin="neumorphic"] [data-slot="textarea"]:disabled,
[data-skin="neumorphic"] [data-slot="select-trigger"]:disabled {
  box-shadow: var(--neu-inset-sm);
  color: var(--muted-foreground);
}

[data-skin="neumorphic"] [data-slot="card"] {
  border: 0;
  border-radius: calc(var(--radius) + 6px);
  background: var(--background);
  box-shadow: var(--neu-raised-lg);
}
/* Cards nested inside an already-elevated specimen step down one level so
   child surfaces don't repeat their parent's elevation. */
[data-skin="neumorphic"] .specimen [data-slot="card"] {
  box-shadow: var(--neu-raised);
}

[data-skin="neumorphic"] [data-slot="popover-content"],
[data-skin="neumorphic"] [data-slot="dropdown-menu-content"],
[data-skin="neumorphic"] [data-slot="context-menu-content"],
[data-skin="neumorphic"] [data-slot="select-content"],
[data-skin="neumorphic"] [data-slot="command"],
[data-skin="neumorphic"] [data-slot="hover-card-content"] {
  border: 0;
  border-radius: calc(var(--radius) + 2px);
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-raised-lg);
}
[data-skin="neumorphic"] [data-slot="tooltip-content"] {
  border-radius: calc(var(--radius) - 4px);
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-raised-sm);
}
[data-skin="neumorphic"] [data-slot="tooltip-content"] svg { fill: var(--background); }

[data-skin="neumorphic"] [data-slot="dropdown-menu-item"][data-highlighted],
[data-skin="neumorphic"] [data-slot="context-menu-item"][data-highlighted],
[data-skin="neumorphic"] [data-slot="select-item"][data-highlighted],
[data-skin="neumorphic"] [data-slot="command-item"][data-selected="true"] {
  border-radius: calc(var(--radius) - 6px);
  background: var(--background);
  color: var(--neu-primary-ink);
  box-shadow: var(--neu-inset-sm);
}

[data-skin="neumorphic"] [data-slot="dialog-content"],
[data-skin="neumorphic"] [data-slot="alert-dialog-content"],
[data-skin="neumorphic"] [data-slot="sheet-content"] {
  border: 0;
  border-radius: calc(var(--radius) + 10px);
  background: var(--background);
  box-shadow: var(--neu-raised-lg);
}

[data-skin="neumorphic"] [data-slot="checkbox"] {
  border: 0;
  border-radius: calc(var(--radius) - 7px);
  background: var(--background);
  box-shadow: var(--neu-inset-sm);
  color: var(--primary-foreground);
  transition: box-shadow 140ms ease, background 140ms ease;
}
[data-skin="neumorphic"] [data-slot="checkbox"][data-state="checked"] {
  background: var(--neu-fill-gradient);
  box-shadow: var(--neu-raised-fill);
}
[data-skin="neumorphic"] [data-slot="radio-group-item"] {
  border: 0;
  border-radius: 9999px;
  background: var(--background);
  box-shadow: var(--neu-inset-sm);
  color: var(--neu-primary-ink);
}

[data-skin="neumorphic"] [data-slot="tabs-list"] {
  border-radius: var(--radius);
  background: var(--background);
  box-shadow: var(--neu-inset);
  padding: 5px;
  gap: 4px;
}
[data-skin="neumorphic"] [data-slot="tabs-trigger"] {
  border: 0;
  border-radius: calc(var(--radius) - 4px);
  background: transparent;
  color: var(--muted-foreground);
}
[data-skin="neumorphic"] [data-slot="tabs-trigger"][data-state="active"] {
  background: var(--background);
  color: var(--neu-primary-ink);
  box-shadow: var(--neu-raised-sm);
  font-weight: 700;
}
/* Variant-aware focus halo for tabs (mirrors the button pattern) so focus
   never falls back to the stock shadcn ring. */
[data-skin="neumorphic"] [data-slot="tabs-trigger"]:focus-visible {
  outline: 0;
  box-shadow: var(--neu-focus-ring);
}
[data-skin="neumorphic"] [data-slot="tabs-trigger"][data-state="active"]:focus-visible {
  box-shadow: var(--neu-raised-sm), var(--neu-focus-ring);
}

[data-skin="neumorphic"] [data-slot="badge"] {
  border: 0;
  border-radius: 9999px;
  box-shadow: var(--neu-raised-sm);
  background: var(--background);
  color: var(--neu-primary-ink);
}
/* Coloured badge gets the fill-tuned shadow, not the grey clay one. */
[data-skin="neumorphic"] [data-slot="badge"][data-variant="default"] {
  background: var(--neu-fill-gradient);
  color: var(--primary-foreground);
  box-shadow: var(--neu-raised-fill);
}
/* Secondary: raised clay with muted ink; outline: carved-in pill. Together
   with default (purple fill) and destructive (red fill) all four read apart. */
[data-skin="neumorphic"] [data-slot="badge"][data-variant="secondary"] {
  color: var(--muted-foreground);
}
[data-skin="neumorphic"] [data-slot="badge"][data-variant="outline"] {
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] [data-slot="badge"][data-variant="destructive"] {
  --neu-fill-color: var(--destructive);
  --neu-fill-gradient: linear-gradient(145deg, var(--neu-fill-color), color-mix(in srgb, var(--neu-fill-color) 90%, #000000));
  --neu-raised-fill:
    inset 0 1px 1px color-mix(in srgb, #ffffff 55%, transparent),
    inset 0 -2px 4px color-mix(in srgb, #000000 18%, transparent),
    var(--neu-d2) var(--neu-d2) calc(var(--neu-blur) * 0.9) color-mix(in srgb, var(--neu-fill-color) 35%, transparent);
  background: var(--neu-fill-gradient);
  color: var(--destructive-foreground);
  box-shadow: var(--neu-raised-fill);
}

/* Switch — inset track when off, glowing raised fill + raised thumb when on. */
[data-skin="neumorphic"] [data-slot="switch"] {
  border: 0;
  border-radius: 9999px;
  background: var(--background);
  box-shadow: var(--neu-inset-sm);
  transition: box-shadow 160ms ease, background 160ms ease;
}
[data-skin="neumorphic"] [data-slot="switch"][data-state="checked"] {
  background: var(--neu-fill-gradient);
  box-shadow:
    var(--neu-inset-sm),
    0 0 var(--neu-glow) color-mix(in srgb, var(--neu-fill-color) 45%, transparent);
}
[data-skin="neumorphic"] [data-slot="switch-thumb"] {
  background: var(--neu-light);
  box-shadow: var(--neu-raised-sm);
}
/* On the coloured ON track the thumb goes solid white with a crisp drop so
   checked reads unmistakably different from the grey OFF state. */
[data-skin="neumorphic"] [data-slot="switch"][data-state="checked"] [data-slot="switch-thumb"] {
  background: var(--primary-foreground);
  box-shadow: 0 1px 3px color-mix(in srgb, #000000 30%, transparent);
}
[data-skin="neumorphic"] [data-slot="switch"]:focus-visible,
[data-skin="neumorphic"] [data-slot="checkbox"]:focus-visible,
[data-skin="neumorphic"] [data-slot="radio-group-item"]:focus-visible {
  outline: 0;
  box-shadow: var(--neu-inset-sm), var(--neu-focus-ring);
}
[data-skin="neumorphic"] [data-slot="checkbox"][data-state="checked"]:focus-visible {
  box-shadow: var(--neu-raised-fill), var(--neu-focus-ring);
}
[data-skin="neumorphic"] [data-slot="switch"][data-state="checked"]:focus-visible {
  box-shadow:
    var(--neu-inset-sm),
    0 0 var(--neu-glow) color-mix(in srgb, var(--neu-fill-color) 45%, transparent),
    var(--neu-focus-ring);
}

[data-skin="neumorphic"] [data-slot="progress"] {
  border-radius: 9999px;
  background: var(--background);
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] [data-slot="progress-indicator"] {
  border-radius: 9999px;
  background: linear-gradient(90deg, var(--primary), var(--chart-2));
}

[data-skin="neumorphic"] [data-slot="slider-track"] {
  border-radius: 9999px;
  background: var(--background);
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] [data-slot="slider-range"] {
  border-radius: 9999px;
  background: linear-gradient(90deg, var(--primary), var(--chart-2));
}
[data-skin="neumorphic"] [data-slot="slider-thumb"] {
  border: 0;
  border-radius: 9999px;
  background: var(--background);
  box-shadow: var(--neu-raised-sm);
}
[data-skin="neumorphic"] [data-slot="slider-thumb"]:focus-visible {
  outline: 0;
  box-shadow: var(--neu-raised-sm), var(--neu-focus-ring);
}

[data-skin="neumorphic"] [data-slot="alert"] {
  border: 0;
  border-radius: calc(var(--radius) + 2px);
  background: var(--background);
  color: var(--foreground);
  box-shadow: var(--neu-inset-sm);
}
[data-skin="neumorphic"] [data-slot="table"] { border-radius: var(--radius); overflow: hidden; }

/* Accordion — kill the stock shadcn border-b hairline (borderless language)
   and replace it with a soft paired light/dark divider carved into the clay. */
[data-skin="neumorphic"] [data-slot="accordion-item"] {
  border-bottom: 0;
  box-shadow: 0 1px 0 var(--neu-light), 0 -1px 0 var(--neu-dark);
}
